#include<bits/stdc++.h>
using namespace std;
const int MAXX = 1005;
char a[MAXX][MAXX];
bool v[1005][1005];
int abc[3][128][2], n, m, x1, y2, xx, yy;

int dx[] = {0, 1, 0, -1};
int dy[] = {-1, 0, 1, 0};
queue<int> q[3];
int bfs(int x, int y) {
	q[0].push(x);
	q[1].push(y);
	q[2].push(0);
    v[x][y]=1;
	while (!q[0].empty()) {
		if (q[0].front() == x1 && q[1].front() == y2) {
			return q[2].front();
		}
		for (int i = 0; i < 4; i++) {
			int mx = q[0].front() + dx[i];
			int my = q[1].front() + dy[i];


			if (mx < 1 || mx > n || my < 1 || my > m) continue;

			if (a[mx][my] != '#') {
				if (a[mx][my] >= 'A' && a[mx][my] <= 'Z') {
					char ch = a[mx][my];
					int idx = ch - 'A' + 1;


					if (abc[1][idx][0] == mx && abc[1][idx][1] == my) {
						mx = abc[2][idx][0];
						my = abc[2][idx][1];
					} else if (abc[2][idx][0] == mx && abc[2][idx][1] == my) {
						mx = abc[1][idx][0];
						my = abc[1][idx][1];
					}
				}
				if (mx >= 1 && mx <= n && my >= 1 && my <= m&&!v[mx][my]) {
                    v[mx][my]=1;
					q[0].push(mx);
					q[1].push(my);
					q[2].push(q[2].front() + 1);
				}
			}
		}
		q[0].pop();
		q[1].pop();
		q[2].pop();

	}
}
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			cin >> a[i][j];
			if (a[i][j] == '=') {
				x1 = i; 
				y2 = j;  
			}
			if (a[i][j] <= 'Z' && a[i][j] >= 'A') {
				if (abc[1][a[i][j] - 'A' + 1][0] != 0) {
					abc[2][a[i][j] - 'A' + 1][0] = i;
					abc[2][a[i][j] - 'A' + 1][1] = j;
				} else {
					abc[1][a[i][j] - 'A' + 1][0] = i;
					abc[1][a[i][j] - 'A' + 1][1] = j;
				}
			}
			if (a[i][j] == '@') {
				xx = i;
				yy = j;
			}


		}
	}
	cout << bfs(xx, yy);

}
